mapper.select:
/*getCommCodeCnt*/
SELECT COUNT(1)
  FROM TM_CODEXM
 WHERE COMM_CODE = #{commCode}

mapper.update:
/*uptCommCode*/
UPDATE TM_CODEXM
   SET CODE_NAME = #{codeName}
     , CODE_EXPL = #{codeExpl}
     , USEE_YSNO = #{useeYsno}
     , UPDT_ADMN = #{updtAdmn}
     , UPDT_DATE = SYSDATE
 WHERE COMM_CODE = #{commCode}

mapper.select:
/*getComdCodeCnt*/
SELECT COUNT(1)
  FROM TB_CODEXD
 WHERE COMM_CODE = #{commCode}
   AND COMD_CODE = #{comdCode}

mapper.update:
/*uptComdCode*/
UPDATE TB_CODEXD
   SET COMD_NAME = #{comdName}
     , CODE_EXPL = #{codeExpl}
     , OPT1_CODE = #{opt1Code}
     , OPT1_NAME = #{opt1Name}
     , OPT2_CODE = #{opt2Code}
     , OPT2_NAME = #{opt2Name}
     , OPT3_CODE = #{opt3Code}
     , OPT3_NAME = #{opt3Name}
     , OPT4_CODE = #{opt4Code}
     , OPT4_NAME = #{opt4Name}
     , USEE_YSNO = #{useeYsno}
     , UPDT_ADMN = #{updtAdmn}
     , UPDT_DATE = SYSDATE
     , SORT_ORDER = #{sortOrder}
 WHERE COMM_CODE = #{commCode}
   AND COMD_CODE = #{comdCode}

mapper.delete:
/*delComdCode*/
DELETE FROM TB_CODEXD
 WHERE COMM_CODE = #{commCode}
   AND COMD_CODE = #{comdCode}

mapper.select:

/*getCodeName*/
SELECT COMD_NAME
  FROM TB_CODEXD
 WHERE COMM_CODE = #{commCode}
   AND COMD_CODE = #{comdCode}
   AND NVL(USEE_YSNO, #{yes}) = #{yes}


/*getCodeNameByComdCode*/
SELECT COMD_NAME
  FROM (
        SELECT COMD_NAME
          FROM TB_CODEXD
         WHERE COMD_CODE = #{comdCode}
           AND NVL(USEE_YSNO, #{yes}) = #{yes}
      ORDER BY COMM_CODE
       )
 WHERE ROWNUM = 1
